import React, { useState } from 'react';
import api from '../utils/api';

export default function CreateAssistant() {
  const [form, setForm] = useState({ name:'', email:'', password:'', confirm_password:'', mobile:'', gender:'', address:'' });
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');
  const [success, setSuccess] = useState('');

  const set = (k:string, v:string) => setForm(f=>({...f,[k]:v}));

  const handleSubmit = async (e:React.FormEvent) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (form.password!==form.confirm_password) { setError('Passwords do not match!'); return; }
    if (form.password.length<6) { setError('Password must be at least 6 characters!'); return; }
    setLoading(true);
    try {
      await api.post('/auth/create-assistant', form);
      setSuccess('Library Assistant account created successfully!');
      setForm({ name:'', email:'', password:'', confirm_password:'', mobile:'', gender:'', address:'' });
    } catch(e:any) { setError(e.response?.data?.message||'Failed to create account'); }
    finally { setLoading(false); }
  };

  const lbl: React.CSSProperties = { display:'block', fontSize:12, fontWeight:600, color:'var(--text-muted)', marginBottom:6 };

  return (
    <div className="page-enter" style={{ padding:'32px 36px', width:'100%' }}>
      <div style={{ marginBottom:28 }}>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:32, fontWeight:700, color:'var(--text)' }}>Create Library Assistant</h1>
        <p style={{ color:'var(--text-muted)', fontSize:14, marginTop:4 }}>Create a new Library Assistant account</p>
      </div>

      <div style={{ maxWidth:580, background:'var(--bg2)', borderRadius:20, padding:32, border:'1px solid var(--border)' }}>

        {/* Role badge */}
        <div style={{ display:'flex',alignItems:'center',gap:14,marginBottom:24,padding:16,background:'var(--bg3)',border:'1px solid var(--border)',borderRadius:14 }}>
          <div style={{ width:48,height:48,background:'linear-gradient(135deg,#c9a84c,#8a6820)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,flexShrink:0 }}>📋</div>
          <div>
            <div style={{ fontSize:14,fontWeight:700,color:'var(--text)' }}>Library Assistant Account</div>
            <div style={{ fontSize:12,color:'var(--text-muted)',marginTop:2 }}>Can issue/return books and manage members</div>
          </div>
        </div>

        {error   && <div style={{ background:'rgba(239,68,68,0.1)',color:'#ef4444',border:'1px solid rgba(239,68,68,0.2)',padding:'12px 16px',borderRadius:10,fontSize:13,marginBottom:16 }}>{error}</div>}
        {success && <div style={{ background:'rgba(16,185,129,0.1)',color:'#10b981',border:'1px solid rgba(16,185,129,0.2)',padding:'12px 16px',borderRadius:10,fontSize:13,marginBottom:16 }}>{success}</div>}

        <form onSubmit={handleSubmit}>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
            <div style={{ gridColumn:'1/-1' }}>
              <label style={lbl}>Full Name *</label>
              <input className="field" value={form.name} onChange={e=>set('name',e.target.value)} placeholder="Assistant's full name" required />
            </div>
            <div style={{ gridColumn:'1/-1' }}>
              <label style={lbl}>Email Address *</label>
              <input className="field" type="email" value={form.email} onChange={e=>set('email',e.target.value.toLowerCase())} placeholder="assistant@library.com" required />
            </div>
            <div>
              <label style={lbl}>Password *</label>
              <input className="field" type="password" value={form.password} onChange={e=>set('password',e.target.value)} placeholder="Min 6 characters" required />
            </div>
            <div>
              <label style={lbl}>Confirm Password *</label>
              <input className="field" type="password" value={form.confirm_password} onChange={e=>set('confirm_password',e.target.value)} placeholder="Repeat password" required />
            </div>
            <div>
              <label style={lbl}>Mobile</label>
              <input className="field" value={form.mobile} onChange={e=>set('mobile',e.target.value)} placeholder="01XXXXXXXXX" />
            </div>
            <div>
              <label style={lbl}>Gender</label>
              <select className="field" value={form.gender} onChange={e=>set('gender',e.target.value)}>
                <option value="">Select gender</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div style={{ gridColumn:'1/-1' }}>
              <label style={lbl}>Address</label>
              <textarea className="field" style={{ minHeight:70, resize:'vertical' }} value={form.address} onChange={e=>set('address',e.target.value)} placeholder="Address (optional)" />
            </div>
          </div>

          {/* Permissions */}
          <div style={{ margin:'20px 0',background:'var(--bg3)',border:'1px solid var(--border)',borderRadius:12,padding:16 }}>
            <div style={{ fontSize:12,fontWeight:700,color:'var(--text)',marginBottom:10 }}>Library Assistant Permissions:</div>
            <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:7 }}>
              {[['✅','Issue & return books'],['✅','Approve borrow requests'],['✅','Manage members'],['✅','Add & edit books'],['❌','Delete books'],['❌','Delete members'],['❌','Create assistants'],['❌','System settings']].map(([icon,text])=>(
                <div key={text} style={{ fontSize:12,color:'var(--text-dim)',display:'flex',alignItems:'center',gap:6 }}>
                  <span>{icon}</span>{text}
                </div>
              ))}
            </div>
          </div>

          <button type="submit" disabled={loading} className="btn-primary" style={{ width:'100%',padding:13,fontSize:14 }}>
            {loading ? 'Creating...' : '+ Create Library Assistant Account'}
          </button>
        </form>
      </div>
    </div>
  );
}
